def insert_in_order(stack, temp):
    if not stack or stack[-1] <= temp:
        stack.append(temp)
        return
    else:
        popped = stack.pop()
        insert_in_order(stack, temp)
        stack.append(popped)
def sort_stack(stack):
    if stack:
        temp = stack.pop()
        sort_stack(stack)
        insert_in_order(stack, temp)
