#include <bits/stdc++.h>
using namespace std;
void insert_in_order(stack<int>& s, int temp){
    if(s.empty() || s.top() <= temp){
        s.push(temp);
        return;
    }else{
        int popped = s.top();
s.pop();
insert_in_order(s, temp);
s.push(popped);
    }
}
void sort_stack(stack<int>& s){
    if(!s.empty()){
        int temp = s.top();
s.pop();
sort_stack(s);
insert_in_order(s, temp);
    }
}
int main(){
    int n;
    cin >> n;
    stack<int> s;
    for(int i = 0; i < n; i++){
        int x;
        cin >> x;
        s.push(x);
    }
    sort_stack(s);
    while(!s.empty()){
        cout << s.top() << endl;
        s.pop();
    }
    return 0;
}
